class Solution {
    public int minimizeXor(int num1, int num2) {
        int setBitsNum2 = Integer.bitCount(num2);
        int result = 0;
        for (int i = 30; i >= 0; i--) {
            int mask = 1 << i;
            if ((num1 & mask) != 0) {
                if (setBitsNum2 > 0) {
                    result |= mask;
                    setBitsNum2--;
                }
            } else {
                if (setBitsNum2 > 0) {
                    result |= mask;
                    setBitsNum2--;
                }
            }
        }
        return result;
    }
}
